import logo from './logo.svg';
import './App.css';
import "./fonts/icomoon/style.css";
import "./css/bootstrap.min.css";
import "./css/jquery-ui.css";
import "./css/owl.carousel.min.css";
import "./css/owl.theme.default.min.css";
import "./css/jquery.fancybox.min.css";
import "./css/bootstrap-datepicker.css";
import "./fonts/flaticon/font/flaticon.css";
import "./css/aos.css";
import "./css/jquery.mb.YTPlayer.min.css";
import Header from "./components/header";
import Footer from "./components/footer";

function App() {
  return (
    <div className="App">
      <header className="App-header">
        <img src={logo} className="App-logo" alt="logo" />
        <p>
          Edit <code>src/App.js</code> and save to reload.
        </p>
        <a
          className="App-link"
          href="https://reactjs.org"
          target="_blank"
          rel="noopener noreferrer"
        >
          Learn React
        </a>
      </header>
      <div className="site-section mb-5 mt-5">
  <div className="container">
      <div className="row justify-content-center">
          <div className="col-lg-7">
              <h3 className="section-title">Customer Service</h3>
              <p style="color:black">For detail information related to the promo, please contact us by telephone +6012345678900.</p>
          </div>
          <div className="col-lg-3 text-center">
              <a className="cta-btn" style="vertical-align: middle!important;" href="tel:+6012345678900" target="_blank"><i class="icon-phone" aria-hidden="true"></i></a>
          </div>
      </div>
  </div>
</div>

    </div>
  );
}

export default App;
